var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"와, 이 정도로 쉬울 상대는 아닌 것 같은데 신형 리액터 성능이 좋긴 하네.","JPN":"わあ、ここまで楽に戦える相手じゃないと思うけど、さすが新型のリアクターってことかな。","ENG":"Huh? They shouldn't have gone down this easy... guess that new Reactor really is something.","TWN":"哇，似乎不是容易對付的對手，新型反應器的性能的確不錯。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"마브카-. 그쪽은 어때요?","JPN":"マブカ、そっちはどうですか？","ENG":"Mavka. How's your side?","TWN":"瑪卡–那邊怎麼樣？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"문제없어. 지금이라면 연전도 가능해.","JPN":"問題ない。今なら連戦もいける。","ENG":"No problems. I could keep going for rounds.","TWN":"沒問題，現在可以連續戰鬥。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"다만…….","JPN":"ただ……","ENG":"Except...","TWN":"但是……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"그림자를 쓰러트렸는데도 침식파 반응이 수그러들지 않고 있어.","JPN":"シャドウを倒したのに、侵食波の反応が収まってない。","ENG":"Even after we dropped the Shadow, the Corruption ray isn't fading.","TWN":"就算擊敗暗影，侵蝕波反應也沒有消退。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"아니, 오히려 사도들의 눈속임에서 벗어난 순간부터 더 강해진 듯한 느낌.","JPN":"ううん、それより使徒の目眩ましを見破った時から更に強くなった気がする。","ENG":"If anything, it's stronger since we broke out of the Apostles' trick.","TWN":"等等，反而從擺脫使徒掩人耳目的手法那一刻開始感覺變得更加強烈。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"그, 그래도 침식파가 거세진 탓에 대균열 중심부로 향하는 길은 명확해요.","JPN":"で、でも、侵食波が強くなったせいで、大亀裂の中心部へ向かう道ははっきりしてます。","ENG":"S-still, the surge of the Corruption ray makes the route to the Grand Dimension Crevice's center clear.","TWN":"但、但因為侵蝕波加劇，通往大峽谷中心的道路很明確。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"작전조 분들의 상황을 모르니… 우, 우선 움직이죠.","JPN":"作戦組の方々の状況がわからないから……と、とりあえず進みましょう。","ENG":"We don't know the operations team's status... l-let's move.","TWN":"不知道作戰組狀況如何…我、我們先行動吧。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"아…!","JPN":"あ……！","ENG":"Ah...!","TWN":"啊…！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예, 예니카. 저기…! 작전조 분들이에요…!!","JPN":"イ、イェニカ、あそこ……！　作戦組の方々です……！！","ENG":"Y-Yanikka, look...! It's them...!!","TWN":"耶、耶妮卡，那裡…！是作戰組的人…！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"휴우-. 늦지 않은 모양이네요. 그쪽이 워커 대령님 맞으시죠?","JPN":"ふう、間に合ったようですね。そっちがウォーカー大佐で合ってますか？","ENG":"Whew! Looks like we're not late. You must be Colonel Walker, right?","TWN":"呼–好像還來得及，你是沃克上校沒錯吧？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"으아-. 군데군데 상처투성이인 것 좀 봐. 혼자서 분투하느라 고생 많으셨겠어요.","JPN":"うわ～傷だらけ。一人で戦うの大変だったでしょうね。","ENG":"Yikes! Look at those cuts all over... You've been holding the line alone.","TWN":"呃啊–看看你渾身是傷，一個人孤軍奮戰一定很辛苦。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"치료키트를 가져왔으니, 우선-.","JPN":"治療キットを持ってきたから、とりあえず……","ENG":"I brought a med-kit, so first–","TWN":"我帶了治療用具過來，就先–"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"……미안하군, 레이디들.","JPN":"……すまない、レディーたち。","ENG":"...I'm sorry, ladies.","TWN":"……抱歉，小姐們。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"여기서… 도망…….","JPN":"ここから……逃げ……","ENG":"Get out... of here...","TWN":"從這裡…逃跑……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"괘, 괘, 괜찮으세요…?!","JPN":"だ、だ、大丈夫ですか……！？","ENG":"A-a-are you okay...?!","TWN":"你、你、你還好嗎…？！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"숨은 붙어 있어. 탈진해서 쓰러진 것뿐.","JPN":"まだ息はある。脱力して倒れただけ。","ENG":"He's breathing. Just collapsed from exhaustion.","TWN":"他還有呼吸，只是虛脫昏過去而已。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"장비의 상태를 보면 가동한계까지 억지로 싸운 듯해.","JPN":"装備の状態からして、稼働限界まで無理して戦ったみたい。","ENG":"Judging by his gear, he fought past the operating limit.","TWN":"看裝備的狀態，應該是硬戰到啟動極限了。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"예, 예니카. 왜 그래요…?","JPN":"イ、イェニカ、どうしたんですか……？","ENG":"Y-Yanikka? What is it...?","TWN":"耶、耶妮卡，妳怎麼了…？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"이 냄새. 실험체일 때 종종 맡았던 냄새와 비슷해요.","JPN":"この匂い。実験体の頃に時々嗅いだ匂いに似てる。","ENG":"This smell. It's similar to what I remember from when I was a test subject.","TWN":"這個味道，跟我是實驗體的時候經常聞到的味道很像。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만 이건… 시약에서 느껴지던 것보다 훨씬 짙은데?","JPN":"でもこれは……試薬の匂いよりもっと濃い。","ENG":"But it's... way thicker than any reagent ever was.","TWN":"但這個…比我從試劑感受到的更濃郁？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"네? 예, 예니카가 받은 실험이라면, 분명…….","JPN":"え？　イ、イェニカがされた実験っていうと、確か……","ENG":"Huh? I-if it's the experiment you got, that would be...","TWN":"什麼？如、如果是耶妮卡接受過的實驗，肯定……"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NATALIA_UNION_NULL_NULL","text":{"KOREA":"창백한… 달?","JPN":"青白い……月？","ENG":"The Pale... Moon?","TWN":"蒼…月？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"NATALIA_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"다들, 뭔가 온다!!","JPN":"みんな、何かが来る！！","ENG":"Heads up! Something's coming!!","TWN":"大家，有東西要來了！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MAVKA_DOLL_NULL_HAIR","text":{"KOREA":"크흡…?!","JPN":"くうっ……！？","ENG":"Kgh...?!","TWN":"咳呃…？！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"오-. 이번 사냥감도 제법 날래잖아?","JPN":"お～今回の獲物も随分と素早いじゃないか。","ENG":"Oh? This quarry's pretty quick too.","TWN":"喔–這次的獵物也很敏捷嘛？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"MAVKA_DOLL_NULL_HAIR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"번개 자식이랑 노는 것도 슬슬 지루했는데, 딱 맞춰 손맛 죽이는 녀석이 나타났어.","JPN":"雷のやつと遊ぶのもそろそろ飽きてきたし、ちょうどいい時に手応えのあるやつが現れてくれたな。","ENG":"I was getting bored playing with the lightning boy over there. Perfect timing for someone who actually feels worth hitting.","TWN":"跟閃電一起玩也開始覺得無聊了，正好出現一個手感絕佳的傢伙。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"너…!!","JPN":"この……！！","ENG":"You...!!","TWN":"妳…！！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"막았다고? 이렇게 간단히?","JPN":"止められた？　こんなにあっさり？","ENG":"You blocked that? That easily?","TWN":"居然這麼輕易擋下來了？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"엉? 설마 방금 그걸 공격이라고 날린 거야?","JPN":"ああ？　まさか今の、攻撃だったのか？","ENG":"Huh? Was that supposed to be an attack?","TWN":"咦？難道妳剛才那是攻擊嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SURPRISE"},"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"잘 봐, 심장이라는 건-.","JPN":"よく見とけ。心臓ってのは……","ENG":"Watch closely. When you go for the heart...!","TWN":"看好了，所謂心臟–"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_IDLE"},"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};